Here's a small demo program in C++ that uses the VAPIX API to control the Axis Q6215-LE camera. This program uses the cURL library for making HTTP requests and includes digest authentication.

First, make sure you have libcurl installed on your system. You can install it using a package manager or by following the instructions on the official cURL website (<https://curl.se/libcurl/>).

Now, create a file named `main.cpp` and paste the following code:
```cpp
#include <iostream>
#include <string>
#include <curl/curl.h>

static size_t WriteCallback(void *contents, size_t size, size_t nmemb, void *userp) {
    ((std::string *)userp)->append((char *)contents, size * nmemb);
    return size * nmemb;
}

void sendVapixRequest(const std::string &url, const std::string &user, const std::string &password) {
    CURL *curl;
    CURLcode res;
    std::string readBuffer;

    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();

    if (curl) {
        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &readBuffer);

        // Enable digest authentication
        curl_easy_setopt(curl, CURLOPT_HTTPAUTH, CURLAUTH_DIGEST);
        curl_easy_setopt(curl, CURLOPT_USERPWD, (user + ":" + password).c_str());

        res = curl_easy_perform(curl);

        if (res != CURLE_OK) {
            std::cerr << "curl_easy_perform() failed: " << curl_easy_strerror(res) << std::endl;
        } else {
            std::cout << "Response:" << std::endl << readBuffer << std::endl;
        }

        curl_easy_cleanup(curl);
    }

    curl_global_cleanup();
}

int main() {
    std::string camera_ip = "192.168.1.2"; // Replace with your camera's IP address
    std::string user = "root"; // Replace with your camera's username
    std::string password = "your_password"; // Replace with your camera's password

    // Move PTZ to a specific position
    std::string url = "http://" + camera_ip + "/axis-cgi/com/ptz.cgi?pan=0&tilt=0&zoom=1000";
    sendVapixRequest(url, user, password);

    return 0;
}
